   229Ôćĺ// Submit answer and get next question
   230Ôćĺrouter.post('/answer', authMiddleware, async (req, res) => {
   231Ôćĺ  const client = await pool.connect();
   232Ôćĺ  try {
   233Ôćĺ    const userId = req.user.id;
   234Ôćĺ    const { sessionId, questionId, answer, timeTaken } = req.body;
   235Ôćĺ
   236Ôćĺ    await client.query('BEGIN');
   237Ôćĺ
   238Ôćĺ    // Get session
   239Ôćĺ    const sessionResult = await client.query(
   240Ôćĺ      'SELECT * FROM assessment_sessions WHERE id = $1 AND user_id = $2',
   241Ôćĺ      [sessionId, userId]
   242Ôćĺ    );
   243Ôćĺ
   244Ôćĺ    if (sessionResult.rows.length === 0) {
   245Ôćĺ      await client.query('ROLLBACK');
   246Ôćĺ      return res.status(404).json({ error: 'Session not found' });
   247Ôćĺ    }
   248Ôćĺ
   249Ôćĺ    const session = sessionResult.rows[0];
   250Ôćĺ
   251Ôćĺ    if (session.status !== 'in_progress') {
   252Ôćĺ      await client.query('ROLLBACK');
   253Ôćĺ      return res.status(400).json({ error: 'Session is not active' });
   254Ôćĺ    }
   255Ôćĺ
   256Ôćĺ    // Get question details
   257Ôćĺ    const questionResult = await client.query(
   258Ôćĺ      'SELECT * FROM assessment_questions WHERE id = $1',
   259Ôćĺ      [questionId]
   260Ôćĺ    );
   261Ôćĺ
   262Ôćĺ    if (questionResult.rows.length === 0) {
   263Ôćĺ      await client.query('ROLLBACK');
   264Ôćĺ      return res.status(404).json({ error: 'Question not found' });
   265Ôćĺ    }
   266Ôćĺ
   267Ôćĺ    const question = questionResult.rows[0];
   268Ôćĺ
   269Ôćĺ    // Evaluate answer
   270Ôćĺ    let isCorrect = false;
   271Ôćĺ    let scorePoints = 0;
   272Ôćĺ    let aiFeedback = null;
   273Ôćĺ
   274Ôćĺ    if (question.question_type === 'multiple_choice') {
   275Ôćĺ      isCorrect = answer === question.correct_answer;
   276Ôćĺ      scorePoints = isCorrect ? (question.difficulty_level || 2) * 10 : 0;
   277Ôćĺ    } else if (question.question_type === 'short_answer') {
   278Ôćĺ      // Use AI to evaluate short answer
   279Ôćĺ      const evaluation = await evaluateShortAnswer(question.question_text, answer, question.explanation);
   280Ôćĺ      isCorrect = evaluation.score >= 70;
   281Ôćĺ      scorePoints = Math.round((evaluation.score / 100) * (question.difficulty_level || 2) * 15);
   282Ôćĺ      aiFeedback = evaluation.feedback;
   283Ôćĺ    }
   284Ôćĺ
   285Ôćĺ    // Check for time anomaly (too fast)
   286Ôćĺ    const expectedMinTime = question.question_type === 'multiple_choice' ? 5 : 15;
   287Ôćĺ    const isTimeAnomaly = timeTaken < expectedMinTime;
   288Ôćĺ
   289Ôćĺ    // Update session
   290Ôćĺ    const questionsAsked = typeof session.questions_asked === 'string'
   291Ôćĺ      ? JSON.parse(session.questions_asked) : (session.questions_asked || []);
   292Ôćĺ    const answersGiven = typeof session.answers_given === 'string'
   293Ôćĺ      ? JSON.parse(session.answers_given) : (session.answers_given || []);
   294Ôćĺ
   295Ôćĺ    answersGiven.push({
   296Ôćĺ      questionId,
   297Ôćĺ      answer,
   298Ôćĺ      isCorrect,
   299Ôćĺ      scorePoints,
   300Ôćĺ      timeTaken,
   301Ôćĺ      timestamp: new Date(),
   302Ôćĺ      aiFeedback
   303Ôćĺ    });
   304Ôćĺ
   305Ôćĺ    const newScore = (session.score || 0) + scorePoints;
   306Ôćĺ    const currentQuestionIndex = (session.current_question_index || 0) + 1;
   307Ôćĺ
   308Ôćĺ    // Adaptive difficulty: increase if correct and no time anomaly, decrease if wrong
   309Ôćĺ    let newDifficulty = session.current_difficulty || 2;
   310Ôćĺ    if (isCorrect && !isTimeAnomaly && newDifficulty < 5) {
   311Ôćĺ      newDifficulty += 1;
   312Ôćĺ    } else if (!isCorrect && newDifficulty > 1) {
   313Ôćĺ      newDifficulty -= 1;
   314Ôćĺ    }
   315Ôćĺ
   316Ôćĺ    const maxDifficultyReached = Math.max(session.max_difficulty_reached || 2, newDifficulty);
   317Ôćĺ    const timeAnomalies = (session.time_anomalies || 0) + (isTimeAnomaly ? 1 : 0);
   318Ôćĺ
   319Ôćĺ    await client.query(`
   320Ôćĺ      UPDATE assessment_sessions
   321Ôćĺ      SET answers_given = $1, score = $2, current_question_index = $3,
   322Ôćĺ          current_difficulty = $4, max_difficulty_reached = $5,
   323Ôćĺ          time_anomalies = $6
   324Ôćĺ      WHERE id = $7
   325Ôćĺ    `, [
   326Ôćĺ      JSON.stringify(answersGiven), newScore, currentQuestionIndex,
   327Ôćĺ      newDifficulty, maxDifficultyReached, timeAnomalies, sessionId
   328Ôćĺ    ]);
   329Ôćĺ
   330Ôćĺ    // Check if assessment is complete (10 questions)
   331Ôćĺ    if (currentQuestionIndex >= 10) {
   332Ôćĺ      await completeAssessment(client, sessionId, userId);
   333Ôćĺ      await client.query('COMMIT');
   334Ôćĺ
   335Ôćĺ      return res.json({
   336Ôćĺ        completed: true,
   337Ôćĺ        score: newScore,
   338Ôćĺ        feedback: isCorrect ? 'Correct!' : 'Incorrect',
   339Ôćĺ        explanation: question.explanation,
   340Ôćĺ        aiFeedback
   341Ôćĺ      });
   342Ôćĺ    }
   343Ôćĺ
   344Ôćĺ    // Get skill for next question
   345Ôćĺ    const skillResult = await client.query(
   346Ôćĺ      'SELECT cs.* FROM candidate_skills cs JOIN assessment_sessions ass ON cs.id = ass.skill_id WHERE ass.id = $1',
   347Ôćĺ      [sessionId]
   348Ôćĺ    );
