   389Ôćĺ        timeLimit: nextQuestion.time_limit_seconds || 120,
   390Ôćĺ        questionNumber: currentQuestionIndex + 1,
   391Ôćĺ        totalQuestions: 10
   392Ôćĺ      }
   393Ôćĺ    });
   394Ôćĺ  } catch (error) {
   395Ôćĺ    await client.query('ROLLBACK');
   396Ôćĺ    console.error('Error submitting answer:', error);
