   445Ôćĺ// Helper: Generate or fetch question
   446Ôćĺasync function generateQuestion(skillName, category, difficulty, client) {
   447Ôćĺ  // Try to find existing question from bank
   448Ôćĺ  const existingResult = await client.query(`
   449Ôćĺ    SELECT * FROM assessment_questions
   450Ôćĺ    WHERE LOWER(skill_category) = LOWER($1) AND difficulty_level = $2
   451Ôćĺ    ORDER BY RANDOM()
   452Ôćĺ    LIMIT 1
   453Ôćĺ  `, [skillName, difficulty]);
   454Ôćĺ
   455Ôćĺ  if (existingResult.rows.length > 0) {
   456Ôćĺ    return existingResult.rows[0];
   457Ôćĺ  }
   458Ôćĺ
   459Ôćĺ  // Generate new question using AI
   460Ôćĺ  const questionType = Math.random() > 0.3 ? 'multiple_choice' : 'short_answer';
   461Ôćĺ  const prompt = `Generate a difficulty ${difficulty}/5 technical assessment question about "${skillName}" (category: ${category}).
   462Ôćĺ
   463ÔćĺQuestion type: ${questionType}
   464Ôćĺ
   465ÔćĺReturn ONLY valid JSON (no markdown, no code blocks):
   466Ôćĺ{
   467Ôćĺ  "question_text": "The question text here",
   468Ôćĺ  "question_type": "${questionType}",
   469Ôćĺ  ${questionType === 'multiple_choice' ? '"options": ["Option A text", "Option B text", "Option C text", "Option D text"],\n  "correct_answer": "Option A text",' : ''}
   470Ôćĺ  "explanation": "Brief explanation of the correct answer",
   471Ôćĺ  "time_limit_seconds": ${questionType === 'multiple_choice' ? '90' : '180'}
   472Ôćĺ}
   473Ôćĺ
   474ÔćĺRequirements:
   475Ôćĺ- Make it practical and relevant to real-world ${skillName} work
   476Ôćĺ- Difficulty ${difficulty}/5 (1=beginner, 5=expert)
   477Ôćĺ- ${questionType === 'multiple_choice' ? 'Provide exactly 4 options. correct_answer must exactly match one of the options.' : 'Ask a question that requires a detailed written response.'}
   478Ôćĺ- Keep question clear and unambiguous`;
   479Ôćĺ
   480Ôćĺ  try {
   481Ôćĺ    const response = await chat(prompt, { maxTokens: 1024 });
   482Ôćĺ
   483Ôćĺ    // Parse response - handle potential markdown code blocks
   484Ôćĺ    let cleanResponse = response.trim();
   485Ôćĺ    if (cleanResponse.startsWith('```')) {
   486Ôćĺ      cleanResponse = cleanResponse.replace(/^```(?:json)?\s*/, '').replace(/\s*```$/, '');
   487Ôćĺ    }
   488Ôćĺ
   489Ôćĺ    const questionData = JSON.parse(cleanResponse);
   490Ôćĺ
   491Ôćĺ    // Validate the response
   492Ôćĺ    if (!questionData.question_text) {
   493Ôćĺ      throw new Error('Missing question_text in AI response');
   494Ôćĺ    }
   495Ôćĺ
   496Ôćĺ    const qType = questionData.question_type || questionType;
   497Ôćĺ    const options = qType === 'multiple_choice' && questionData.options
   498Ôćĺ      ? (typeof questionData.options === 'string' ? questionData.options : JSON.stringify(questionData.options))
   499Ôćĺ      : null;
   500Ôćĺ
   501Ôćĺ    // Save to database
   502Ôćĺ    const result = await client.query(`
   503Ôćĺ      INSERT INTO assessment_questions
   504Ôćĺ      (skill_category, difficulty_level, question_type, question_text, options, correct_answer, explanation, time_limit_seconds)
   505Ôćĺ      VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
   506Ôćĺ      RETURNING *
   507Ôćĺ    `, [
   508Ôćĺ      skillName,
   509Ôćĺ      difficulty,
   510Ôćĺ      qType,
   511Ôćĺ      questionData.question_text,
   512Ôćĺ      options,
   513Ôćĺ      questionData.correct_answer || null,
   514Ôćĺ      questionData.explanation || 'See the correct answer above.',
   515Ôćĺ      questionData.time_limit_seconds || (qType === 'multiple_choice' ? 90 : 180)
   516Ôćĺ    ]);
   517Ôćĺ
   518Ôćĺ    return result.rows[0];
   519Ôćĺ  } catch (error) {
   520Ôćĺ    console.error('Error generating AI question:', error);
   521Ôćĺ
   522Ôćĺ    // Fallback: try any question from the bank
   523Ôćĺ    const fallbackResult = await client.query(`
   524Ôćĺ      SELECT * FROM assessment_questions
   525Ôćĺ      ORDER BY RANDOM()
   526Ôćĺ      LIMIT 1
   527Ôćĺ    `);
   528Ôćĺ
   529Ôćĺ    if (fallbackResult.rows.length > 0) {
   530Ôćĺ      return fallbackResult.rows[0];
   531Ôćĺ    }
   532Ôćĺ
   533Ôćĺ    // Last resort: create a hardcoded question
   534Ôćĺ    const fallbackInsert = await client.query(`
   535Ôćĺ      INSERT INTO assessment_questions
   536Ôćĺ      (skill_category, difficulty_level, question_type, question_text, options, correct_answer, explanation, time_limit_seconds)
   537Ôćĺ      VALUES ($1, $2, 'multiple_choice', $3, $4, $5, $6, 90)
   538Ôćĺ      RETURNING *
   539Ôćĺ    `, [
   540Ôćĺ      skillName,
   541Ôćĺ      difficulty,
   542Ôćĺ      `Which of the following best describes a key concept in ${skillName}?`,
   543Ôćĺ      JSON.stringify([
   544Ôćĺ        `A fundamental principle of ${skillName} that enables modularity`,
