   587Ôćĺ// Helper: Complete assessment
   588Ôćĺasync function completeAssessment(client, sessionId, userId) {
   589Ôćĺ  const sessionResult = await client.query(
   590Ôćĺ    'SELECT * FROM assessment_sessions WHERE id = $1',
   591Ôćĺ    [sessionId]
   592Ôćĺ  );
   593Ôćĺ  const session = sessionResult.rows[0];
   594Ôćĺ
   595Ôćĺ  // Get skill name for the title
   596Ôćĺ  const skillResult = await client.query(
   597Ôćĺ    'SELECT skill_name FROM candidate_skills WHERE id = $1',
   598Ôćĺ    [session.skill_id]
   599Ôćĺ  );
   600Ôćĺ  const skillName = skillResult.rows.length > 0 ? skillResult.rows[0].skill_name : 'Unknown';
   601Ôćĺ
   602Ôćĺ  // Calculate anti-cheat score (100 = clean, lower = suspicious)
   603Ôćĺ  let antiCheatScore = 100;
   604Ôćĺ  antiCheatScore -= (session.tab_switches || 0) * 5;
   605Ôćĺ  antiCheatScore -= (session.copy_paste_attempts || 0) * 10;
   606Ôćĺ  antiCheatScore -= (session.time_anomalies || 0) * 5;
   607Ôćĺ  antiCheatScore = Math.max(0, antiCheatScore);
   608Ôćĺ
   609Ôćĺ  const passed = (session.score || 0) >= 60 && antiCheatScore >= 50;
   610Ôćĺ
   611Ôćĺ  // Mark session complete
   612Ôćĺ  await client.query(
   613Ôćĺ    "UPDATE assessment_sessions SET status = 'completed', completed_at = NOW() WHERE id = $1",
   614Ôćĺ    [sessionId]
   615Ôćĺ  );
   616Ôćĺ
   617Ôćĺ  // Create skill assessment record
   618Ôćĺ  const assessmentResult = await client.query(`
   619Ôćĺ    INSERT INTO skill_assessments
   620Ôćĺ    (user_id, skill_id, session_id, assessment_type, title, score, max_score, passed,
   621Ôćĺ     anti_cheat_score, behavioral_flags, duration_seconds, started_at, completed_at)
   622Ôćĺ    VALUES ($1, $2, $3, 'dynamic', $4, $5, 100, $6, $7, $8,
   623Ôćĺ            EXTRACT(EPOCH FROM (NOW() - $9::timestamp)), $9, NOW())
   624Ôćĺ    RETURNING id
   625Ôćĺ  `, [
   626Ôćĺ    userId,
   627Ôćĺ    session.skill_id,
   628Ôćĺ    sessionId,
   629Ôćĺ    `${skillName} Assessment`,
   630Ôćĺ    session.score || 0,
   631Ôćĺ    passed,
   632Ôćĺ    antiCheatScore,
   633Ôćĺ    JSON.stringify({
   634Ôćĺ      tab_switches: session.tab_switches || 0,
   635Ôćĺ      copy_paste: session.copy_paste_attempts || 0,
   636Ôćĺ      time_anomalies: session.time_anomalies || 0,
   637Ôćĺ      max_difficulty: session.max_difficulty_reached || 2
   638Ôćĺ    }),
   639Ôćĺ    session.started_at
   640Ôćĺ  ]);
   641Ôćĺ
   642Ôćĺ  // If passed, mark skill as verified
   643Ôćĺ  if (passed) {
   644Ôćĺ    await client.query(
   645Ôćĺ      'UPDATE candidate_skills SET is_verified = true, verified_at = NOW(), verified_score = $1 WHERE id = $2',
   646Ôćĺ      [session.score, session.skill_id]
   647Ôćĺ    );
   648Ôćĺ  }
   649Ôćĺ
   650Ôćĺ  // Event-driven: Feed assessment score into OmniScore technical component
   651Ôćĺ  try {
